                // Play the game here
                break;
            default:
                printf("Unknown game state %d\n", game_state);
                break;
        }

        // Draw the game objects
        SDL_RenderClear(renderer);
        SDL_RenderCopy(renderer, snake_image, NULL, NULL);
        SDL_RenderCopy(renderer, food_image, NULL, NULL);
        SDL_RenderCopy(renderer, wall_image, NULL, NULL);

        // Update the screen
        SDL_RenderPresent(renderer);

        // Handle frame drops
        SDL_Delay(16);
    }

    // Clean up
    IMG_Free(snake_image);
    IMG_Free(food_image);
    IMG_Free(wall_image);

    SDL_Quit();

    return 0;
}
