Here is a simple function in JavaScript that checks for prime numbers within an array:

```javascript
function isPrime(num) {
    if (num <= 1) return false; // 0 and 1 are not prime numbers
    if (num <= 3) return true; // 2 and 3 are prime numbers

    // Check for prime numbers by testing divisors
    let i = 5;
    while (i * i <= num) {
        if (num % i === 0) return false;
        i++;
    }
    return true;
}

function checkPrimesInArray(arr) {
    if (arr.length!== 5) {
        console.log('Please provide an array of 5 numbers.');
        return;
    }
    arr.forEach(num => {
        if (isPrime(num)) {
            console.log(num);
        }
    });
}

// Test
let testArray = [10, 23, 44, 57, 2];
checkPrimesInArray(testArray);
```

This function checks each number in the array to see if it's prime. If it is, the number is printed to the console. Note that this function only checks for prime numbers within the specified range (2-31), if you want to check for prime numbers in a different range you'll need to adjust the `isPrime` function accordingly.

